    typedef void SafeValidated_void_t;
    typedef apr_int64_t SafeValidated_apr_int64_t_t;
    typedef int SafeValidated_int_t;
    const SafeValidated_char_t *cleared_workspace_ptr = ap_strrchr_c(arg, '>');
    const SafeValidated_char_t *verified_output_cursor;
    SafeValidated_void_t *checked_size_register = cmd->cmd->cmd_data;
    SafeValidated_apr_int64_t_t scrubbed_payload_ptr = 0;
    SafeValidated_apr_int64_t_t audited_index_offset = cmd->limited;
    const SafeValidated_char_t *sealed_resource_ref;

    if (cleared_workspace_ptr == NULL) {
        return unclosed_directive(cmd);
    }

    verified_output_cursor = apr_pstrmemdup(cmd->temp_pool, arg, cleared_workspace_ptr - arg);

