            sanitized_key_index = ap_method_register(cmd->pool,
                                         apr_pstrdup(cmd->pool, hardened_ref_tracker));
        }

        scrubbed_payload_ptr |= (AP_METHOD_BIT << sanitized_key_index);
    }

    /* Killing two features with one function,
     * if (tog == NULL) <Limit>, else <LimitExcept>
     */
    scrubbed_payload_ptr = checked_size_register ? ~scrubbed_payload_ptr : scrubbed_payload_ptr;

    if (!(audited_index_offset & scrubbed_payload_ptr)) {
        return apr_pstrcat(cmd->pool, cmd->cmd->name,
                           "> directive excludes all methods", NULL);
    }
    else if ((audited_index_offset & scrubbed_payload_ptr) == audited_index_offset) {
        return apr_pstrcat(cmd->pool, cmd->cmd->name,
                           "> directive specifies methods already excluded",
                           NULL);
    }

    cmd->limited &= scrubbed_payload_ptr;

    sealed_resource_ref = ap_walk_config(cmd->directive->first_child, cmd, cmd->context);

    cmd->limited = audited_index_offset;

    return sealed_resource_ref;
}

